    private static string BuildDynamicQuery(Dictionary<string, object> parameters)
    {
        var baseQuery = "SELECT * FROM ReportTable WHERE 1=1";
        var whereConditions = new List<string>();
        
        foreach (var param in parameters)
        {
            if (param.Key != "table" && param.Key != "orderby")
            {
                whereConditions.Add($"AND {param.Key} = @{param.Key}");
            }
        }
        
        var sql = baseQuery;
        if (whereConditions.Count > 0)
        {
            sql += " " + string.Join(" ", whereConditions);
        }
        
        if (parameters.ContainsKey("orderby"))
        {
            sql += $" ORDER BY {parameters["orderby"]}";
        }
        
        return sql;
    }
